fn input_to_substrate(input: Input) -> substrate::CompatInput {
    match input {
        Input::CreateRun(payload) => substrate::CompatInput::CreateRun {
            step_ids: payload.step_ids,
            ordered_steps: payload.ordered_steps,
            step_has_conditions: payload.step_has_conditions,
            step_dependencies: payload.step_dependencies,
            step_dependency_modes: payload.step_dependency_modes,
            step_branches: payload.step_branches,
            step_collection_policies: payload.step_collection_policies,
            step_quorum_thresholds: payload.step_quorum_thresholds,
            escalation_threshold: payload.escalation_threshold,
            max_step_retries: payload.max_step_retries,
            max_active_nodes: payload.max_active_nodes,
            max_active_frames: payload.max_active_frames,
            max_frame_depth: payload.max_frame_depth,
        },
        Input::StartRun(_payload) => substrate::CompatInput::StartRun,
        Input::DispatchStep(payload) => substrate::CompatInput::DispatchStep {
            step_id: payload.step_id,
        },
        Input::CompleteStep(payload) => substrate::CompatInput::CompleteStep {
            step_id: payload.step_id,
        },
        Input::RecordStepOutput(payload) => substrate::CompatInput::RecordStepOutput {
            step_id: payload.step_id,
        },
        Input::ConditionPassed(payload) => substrate::CompatInput::ConditionPassed {
            step_id: payload.step_id,
        },
        Input::ConditionRejected(payload) => substrate::CompatInput::ConditionRejected {
            step_id: payload.step_id,
        },
        Input::FailStep(payload) => substrate::CompatInput::FailStep {
            step_id: payload.step_id,
        },
        Input::SkipStep(payload) => substrate::CompatInput::SkipStep {
            step_id: payload.step_id,
        },
        Input::ProjectFrameStepStatus(payload) => substrate::CompatInput::ProjectFrameStepStatus {
            step_id: payload.step_id,
            step_status: payload.step_status,
            append_failure_ledger: payload.append_failure_ledger,
        },
        Input::CancelStep(payload) => substrate::CompatInput::CancelStep {
            step_id: payload.step_id,
        },
        Input::RegisterTargets(payload) => substrate::CompatInput::RegisterTargets {
            step_id: payload.step_id,
            target_count: payload.target_count,
        },
        Input::RecordTargetSuccess(payload) => substrate::CompatInput::RecordTargetSuccess {
            step_id: payload.step_id,
            target_id: payload.target_id,
        },
        Input::RecordTargetTerminalFailure(payload) => {
            substrate::CompatInput::RecordTargetTerminalFailure {
                step_id: payload.step_id,
            }
        }
        Input::RecordTargetCanceled(payload) => substrate::CompatInput::RecordTargetCanceled {
            step_id: payload.step_id,
            target_id: payload.target_id,
        },
        Input::RecordTargetFailure(payload) => substrate::CompatInput::RecordTargetFailure {
            step_id: payload.step_id,
            target_id: payload.target_id,
            retry_key: payload.retry_key,
        },
        Input::RegisterReadyFrame(payload) => substrate::CompatInput::RegisterReadyFrame {
            frame_id: payload.frame_id,
        },
        Input::PumpNodeScheduler(_payload) => substrate::CompatInput::PumpNodeScheduler,
        Input::RegisterPendingBodyFrame(payload) => {
            substrate::CompatInput::RegisterPendingBodyFrame {
                loop_instance_id: payload.loop_instance_id,
                depth: payload.depth,
            }
        }
        Input::PumpFrameScheduler(_payload) => substrate::CompatInput::PumpFrameScheduler,
        Input::NodeExecutionReleased(payload) => substrate::CompatInput::NodeExecutionReleased {
            frame_id: payload.frame_id,
        },
        Input::FrameTerminated(payload) => substrate::CompatInput::FrameTerminated {
            frame_id: payload.frame_id,
        },
        Input::TerminalizeCompleted(_payload) => substrate::CompatInput::TerminalizeCompleted,
        Input::TerminalizeFailed(_payload) => substrate::CompatInput::TerminalizeFailed,
        Input::TerminalizeCanceled(_payload) => substrate::CompatInput::TerminalizeCanceled,
    }
}

fn effect_from_substrate(effect: substrate::CompatEffect) -> Effect {
    match effect {
        substrate::CompatEffect::EmitFlowRunNotice { run_status } => {
            Effect::EmitFlowRunNotice(effects::EmitFlowRunNotice { run_status })
        }
        substrate::CompatEffect::EmitStepNotice {
            step_id,
            step_status,
        } => Effect::EmitStepNotice(effects::EmitStepNotice {
            step_id,
            step_status,
        }),
        substrate::CompatEffect::AppendFailureLedger { step_id } => {
            Effect::AppendFailureLedger(effects::AppendFailureLedger { step_id })
        }
        substrate::CompatEffect::PersistStepOutput { step_id } => {
            Effect::PersistStepOutput(effects::PersistStepOutput { step_id })
        }
        substrate::CompatEffect::AdmitStepWork { step_id } => {
            Effect::AdmitStepWork(effects::AdmitStepWork { step_id })
        }
        substrate::CompatEffect::FlowTerminalized { run_status } => {
            Effect::FlowTerminalized(effects::FlowTerminalized { run_status })
        }
        substrate::CompatEffect::EscalateSupervisor { step_id } => {
            Effect::EscalateSupervisor(effects::EscalateSupervisor { step_id })
        }
        substrate::CompatEffect::ProjectTargetSuccess { step_id, target_id } => {
            Effect::ProjectTargetSuccess(effects::ProjectTargetSuccess { step_id, target_id })
        }
        substrate::CompatEffect::ProjectTargetFailure { step_id, target_id } => {
            Effect::ProjectTargetFailure(effects::ProjectTargetFailure { step_id, target_id })
        }
        substrate::CompatEffect::ProjectTargetCanceled { step_id, target_id } => {
            Effect::ProjectTargetCanceled(effects::ProjectTargetCanceled { step_id, target_id })
        }
        substrate::CompatEffect::GrantNodeSlot { frame_id } => {
            Effect::GrantNodeSlot(effects::GrantNodeSlot { frame_id })
        }
        substrate::CompatEffect::GrantBodyFrameStart { loop_instance_id } => {
            Effect::GrantBodyFrameStart(effects::GrantBodyFrameStart { loop_instance_id })
        }
    }
}

